            //
            aOrbiterH = (aOrbiterH + aOrbiterK) + 6373559542002699718U;
            aOrbiterA = ((aOrbiterA ^ aOrbiterH) ^ 11694562937392022505U) ^ aOrbiterUpdateSaltC[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 9311557972331218597U), 21U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterB) + 3308736483775453062U;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 12749929710650475901U;
            aOrbiterE = RotL64((aOrbiterE * 248428400724560945U), 35U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterJ) + 1569528215675579656U;
