            aOrbiterF = ((aWandererB + RotL64(aIngress, 57U)) + 12928600185788857701U) + aNonceWordO;
            aOrbiterI = ((aWandererC + RotL64(aPrevious, 19U)) + 14240723153798267172U) + aOrbiterAssignSaltD[((aIndex + 26U)) & S_SALT1];
