            //
            aOrbiterF = (aOrbiterF + aOrbiterI) + 6190745292098482871U;
            aOrbiterA = ((aOrbiterA ^ aOrbiterF) ^ 8065418693975056902U) ^ aOrbiterUpdateSaltF[((aIndex + 10U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 6414621418430102589U), 23U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterD) + 12111755051718111803U;
            aOrbiterK = (aOrbiterK ^ aOrbiterI) ^ 7605877769709909297U;
            aOrbiterK = RotL64((aOrbiterK * 17525248694315944599U), 41U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 5969794501112646237U;
            aOrbiterI = (aOrbiterI ^ aOrbiterJ) ^ 5127559299360591476U;
            aOrbiterI = RotL64((aOrbiterI * 4521563633438853069U), 11U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterJ) + 10593847754747739786U;
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 4401750688524310121U;
